CREATE TABLE IF NOT EXISTS best_seeds (
    rank INT,
    seed BIGINT,
    desert_to_snow_dist INT,
    villages INT,
    unique_villages INT,
    bonus_points INT,
    spawn_in_between BOOLEAN,
    has_mansion BOOLEAN,
    desert_area INT,
    snow_area INT,
    swamp_area INT,
    savanna_area INT,
    plains_area INT,
    taiga_area INT,
    mushroom_area INT,
    old_growth_area INT,
    stony_peaks_area INT,
    pale_garden_area INT,
    chunkbase_url TEXT
);

